use rand::Rng;
use rand::distributions::Alphanumeric;

const TOKEN_LENGTH: usize = 40;

/// Generates a cryptographically secure random API token of 40 alphanumeric characters.
///
/// Uses `rand::thread_rng()` which, as of rand 0.8+, is backed by a
/// cryptographically secure PRNG (ChaCha12 seeded from the OS entropy source
/// via `getrandom`). This satisfies the requirement for cryptographically
/// secure randomness suitable for authentication tokens.
pub fn generate_api_token() -> String {
    let mut rng = rand::thread_rng();
    let token: String = (0..TOKEN_LENGTH)
        .map(|_| rng.sample(Alphanumeric) as char)
        .collect();
    token
}

/// Generates multiple unique API tokens at once.
pub fn generate_api_tokens(count: usize) -> Vec<String> {
    let mut tokens = Vec::with_capacity(count);
    let mut rng = rand::thread_rng();

    for _ in 0..count {
        let token: String = (0..TOKEN_LENGTH)
            .map(|_| rng.sample(Alphanumeric) as char)
            .collect();
        tokens.push(token);
    }

    tokens
}

/// Validates that a token has the expected format (40 alphanumeric characters).
pub fn is_valid_token_format(token: &str) -> bool {
    token.len() == TOKEN_LENGTH && token.chars().all(|c| c.is_ascii_alphanumeric())
}

